    INSERT INTO public.exam_questions
      (question_text, options, correct_answer, exam_type, level, section, difficulty, explanation, is_active, transcript, image_prompt)
    VALUES
  (E'雨が降っ＿、傘を持って行きます。', '["た","て","る","ない"]'::jsonb, 0, 'jlpt', 'n4', 'grammar', 3, E'たら/て setelah hujan turun.', true, NULL, NULL),
  (E'本を読ん＿、寝ます。', '["だ","で","て","に"]'::jsonb, 1, 'jlpt', 'n4', 'grammar', 3, E'Vて、V = setelah membaca, tidur.', true, NULL, NULL),
  (E'日本語＿話せますか。', '["は","が","を","に"]'::jsonb, 1, 'jlpt', 'n4', 'grammar', 3, E'Kemampuan memakai が.', true, NULL, NULL),
  (E'この漢字＿読めますか。', '["は","が","を","に"]'::jsonb, 1, 'jlpt', 'n4', 'grammar', 3, E'可能形 + が untuk kemampuan.', true, NULL, NULL),
  (E'東京＿行きたいです。', '["は","が","を","に"]'::jsonb, 3, 'jlpt', 'n4', 'grammar', 3, E'行きたい + に untuk tujuan.', true, NULL, NULL),
  (E'寿司＿食べたいです。', '["は","が","を","に"]'::jsonb, 1, 'jlpt', 'n4', 'grammar', 3, E'食べたい + が untuk objek keinginan.', true, NULL, NULL),
  (E'京都＿大阪より静かです。', '["は","が","を","の"]'::jsonb, 0, 'jlpt', 'n4', 'grammar', 3, E'Perbandingan topik memakai は.', true, NULL, NULL),
  (E'バス＿電車より遅いです。', '["は","が","を","の"]'::jsonb, 0, 'jlpt', 'n4', 'grammar', 3, E'Topik perbandingan memakai は.', true, NULL, NULL),
  (E'早く起き＿、間に合いました。', '["たら","て","る","ない"]'::jsonb, 0, 'jlpt', 'n4', 'grammar', 3, E'たら = jika/setelah.', true, NULL, NULL),
  (E'安けれ＿、買います。', '["ば","たら","て","る"]'::jsonb, 0, 'jlpt', 'n4', 'grammar', 3, E'ければ/ば = kondisi.', true, NULL, NULL),
  (E'宿題をし＿、遊びに行きます。', '["ないで","なくて","ない","なく"]'::jsonb, 0, 'jlpt', 'n4', 'grammar', 3, E'ないで = tanpa melakukan.', true, NULL, NULL),
  (E'タバコを吸わ＿ください。', '["ないで","なくて","ない","なく"]'::jsonb, 0, 'jlpt', 'n4', 'grammar', 3, E'ないでください = jangan lakukan.', true, NULL, NULL),
  (E'彼＿会いたいです。', '["は","が","を","に"]'::jsonb, 3, 'jlpt', 'n4', 'grammar', 3, E'会う + に untuk orang.', true, NULL, NULL),
  (E'友達＿手紙を書きました。', '["は","が","に","へ"]'::jsonb, 2, 'jlpt', 'n4', 'grammar', 3, E'書く + に untuk penerima.', true, NULL, NULL),
  (E'先生＿質問しました。', '["は","が","を","に"]'::jsonb, 3, 'jlpt', 'n4', 'grammar', 3, E'質問する + に untuk orang.', true, NULL, NULL),
  (E'電車＿乗り換えます。', '["は","が","を","に"]'::jsonb, 3, 'jlpt', 'n4', 'grammar', 3, E'乗り換える + に.', true, NULL, NULL),
  (E'窓＿開けてください。', '["は","が","を","に"]'::jsonb, 2, 'jlpt', 'n4', 'grammar', 3, E'開ける + を.', true, NULL, NULL),
  (E'もっと勉強し＿、合格できます。', '["たら","て","れば","ない"]'::jsonb, 2, 'jlpt', 'n4', 'grammar', 3, E'ば/れば = jika lebih belajar.', true, NULL, NULL),
  (E'時間があれ＿、行きます。', '["ば","たら","て","る"]'::jsonb, 0, 'jlpt', 'n4', 'grammar', 3, E'あれば = jika ada waktu.', true, NULL, NULL),
  (E'仕事が終わっ＿、飲みに行きましょう。', '["たら","て","る","ない"]'::jsonb, 0, 'jlpt', 'n4', 'grammar', 3, E'たら = setelah selesai kerja.', true, NULL, NULL),
  (E'この本は面白く＿、読みました。', '["て","た","ない","る"]'::jsonb, 0, 'jlpt', 'n4', 'grammar', 3, E'Adjい→くて menghubungkan alasan.', true, NULL, NULL),
  (E'道が込んで＿、遅れました。', '["いて","いる","いた","いない"]'::jsonb, 0, 'jlpt', 'n4', 'grammar', 3, E'Vていて = karena sedang macet.', true, NULL, NULL),
  (E'彼女＿プレゼントをあげました。', '["は","が","を","に"]'::jsonb, 3, 'jlpt', 'n4', 'grammar', 3, E'あげる + に untuk penerima.', true, NULL, NULL),
  (E'母＿料理を教えてもらいました。', '["は","が","を","に"]'::jsonb, 3, 'jlpt', 'n4', 'grammar', 3, E'もらう + に untuk pemberi.', true, NULL, NULL),
  (E'図書館＿本を借りました。', '["は","が","を","で"]'::jsonb, 3, 'jlpt', 'n4', 'grammar', 3, E'Lokasi aktivitas memakai で.', true, NULL, NULL),
  (E'来週＿旅行に行きます。', '["は","が","を","に"]'::jsonb, 0, 'jlpt', 'n4', 'grammar', 3, E'Waktu sebagai topik memakai は.', true, NULL, NULL),
  (E'毎日＿三時間勉強します。', '["は","が","を","に"]'::jsonb, 0, 'jlpt', 'n4', 'grammar', 3, E'Durasi kebiasaan + は.', true, NULL, NULL),
  (E'彼＿知っていますか。', '["は","が","を","に"]'::jsonb, 0, 'jlpt', 'n4', 'grammar', 3, E'Topik pertanyaan memakai は.', true, NULL, NULL),
  (E'どちら＿好きですか。', '["は","が","を","に"]'::jsonb, 1, 'jlpt', 'n4', 'grammar', 3, E'好き + が.', true, NULL, NULL),
  (E'何＿買いましたか。', '["は","が","を","に"]'::jsonb, 2, 'jlpt', 'n4', 'grammar', 3, E'買う + を.', true, NULL, NULL);
    INSERT INTO public.exam_questions
      (question_text, options, correct_answer, exam_type, level, section, difficulty, explanation, is_active, transcript, image_prompt)
    VALUES
  (E'「田中さんは来週、大阪に出張します。三日間いません。」— 田中さんはいつ出張しますか？', '["今週","来週","先週","毎週"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'来週 = minggu depan.', true, NULL, NULL),
  (E'「田中さんは来週、大阪に出張します。三日間いません。」— 何日いませんか？', '["一日","二日","三日","四日"]'::jsonb, 2, 'jlpt', 'n4', 'reading', 3, E'三日間 = tiga hari.', true, NULL, NULL),
  (E'「昨日、雨が降ったので、傘を持って行きました。」— なぜ傘を持ちましたか？', '["暑いから","雨だから","風だから","雪だから"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'雨が降った = karena hujan.', true, NULL, NULL),
  (E'「このレストランは安くて、おいしいです。」— レストランはどうですか？', '["高くてまずい","安くておいしい","遠くて不便","新しくてきれい"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'安くておいしい = murah dan enak.', true, NULL, NULL),
  (E'「山田さんは毎朝、六時に起きて、ジョギングをします。」— 山田さんは何時に起きますか？', '["五時","六時","七時","八時"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'六時 = jam 6.', true, NULL, NULL),
  (E'「山田さんは毎朝、六時に起きて、ジョギングをします。」— 朝、何をしますか？', '["散歩","ジョギング","泳ぐ","読書"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'ジョギング = jogging.', true, NULL, NULL),
  (E'「来月、友達の結婚式があります。プレゼントを買います。」— 何を買いますか？', '["服","プレゼント","花","ケーキ"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'プレゼント untuk pernikahan.', true, NULL, NULL),
  (E'「電車が遅れたので、会議に遅れました。」— なぜ遅れましたか？', '["電車が遅れた","寝坊した","道に迷った","病気だ"]'::jsonb, 0, 'jlpt', 'n4', 'reading', 3, E'電車が遅れた = kereta terlambat.', true, NULL, NULL),
  (E'「夏休みに海に行きたいです。泳ぎたいです。」— 何をしたいですか？', '["山に登る","泳ぐ","スキー","釣り"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'泳ぎたい = ingin berenang.', true, NULL, NULL),
  (E'「この仕事は難しいですが、面白いです。」— 仕事はどうですか？', '["簡単でつまらない","難しいが面白い","簡単で楽しい","難しくて疲れる"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'難しいが面白い.', true, NULL, NULL),
  (E'「佐藤さんは日本語が上手です。毎日勉強しています。」— 佐藤さんは何が上手ですか？', '["英語","日本語","数学","料理"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'日本語が上手.', true, NULL, NULL),
  (E'「駅から歩いて十五分です。バスもあります。」— 駅から何分ですか？', '["五分","十分","十五分","二十分"]'::jsonb, 2, 'jlpt', 'n4', 'reading', 3, E'十五分 = 15 menit.', true, NULL, NULL),
  (E'「明日の天気は雨です。傘を忘れないでください。」— 明日の天気は？', '["晴れ","雨","雪","曇り"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'雨 = hujan.', true, NULL, NULL),
  (E'「母の誕生日に花を贈りました。とても喜びました。」— 何を贈りましたか？', '["ケーキ","花","服","本"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'花 = bunga.', true, NULL, NULL),
  (E'「新しいパソコンを買いました。仕事が楽になりました。」— 何を買いましたか？', '["車","パソコン","テレビ","カメラ"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'パソコン = komputer.', true, NULL, NULL),
  (E'「彼は毎週、土曜日にボランティアをしています。」— いつボランティアをしますか？', '["金曜日","土曜日","日曜日","月曜日"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'土曜日 = Sabtu.', true, NULL, NULL),
  (E'「この薬は食後に飲んでください。一日三回です。」— 一日何回ですか？', '["一回","二回","三回","四回"]'::jsonb, 2, 'jlpt', 'n4', 'reading', 3, E'三回 = tiga kali.', true, NULL, NULL),
  (E'「会議は三時から五時までです。二時間です。」— 会議は何時間ですか？', '["一時間","二時間","三時間","四時間"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'二時間 = dua jam.', true, NULL, NULL),
  (E'「彼女はピアノが弾けます。子供の時から習っています。」— 彼女は何ができますか？', '["歌","ピアノ","ダンス","絵"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'ピアノが弾ける.', true, NULL, NULL),
  (E'「来週のテストのために、毎日復習しています。」— 何のために復習していますか？', '["面接","テスト","旅行","パーティー"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'テスト = ujian.', true, NULL, NULL),
  (E'「この道をまっすぐ行って、右に曲がってください。」— どこに曲がりますか？', '["左","右","前","後"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'右に曲がる = belok kanan.', true, NULL, NULL),
  (E'「荷物が重いので、タクシーに乗りました。」— なぜタクシーに乗りましたか？', '["安いから","速いから","重いから","近いから"]'::jsonb, 2, 'jlpt', 'n4', 'reading', 3, E'荷物が重い = barang berat.', true, NULL, NULL),
  (E'「彼は風邪をひいたので、今日は休みます。」— 彼はどうしましたか？', '["風邪","怪我","頭痛","腹痛"]'::jsonb, 0, 'jlpt', 'n4', 'reading', 3, E'風邪をひく = masuk angin.', true, NULL, NULL),
  (E'「この店は人気があります。いつも込んでいます。」— 店はどうですか？', '["空いている","込んでいる","閉まっている","新しい"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'込んでいる = ramai/penuh.', true, NULL, NULL),
  (E'「来月、引っ越しします。新しいアパートに住みます。」— 来月、何をしますか？', '["旅行","引っ越し","結婚","就職"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'引っ越し = pindah rumah.', true, NULL, NULL),
  (E'「彼は英語もフランス語も話せます。三か国語です。」— 何か国語話せますか？', '["一","二","三","四"]'::jsonb, 2, 'jlpt', 'n4', 'reading', 3, E'三か国語 = tiga bahasa.', true, NULL, NULL),
  (E'「試験に合格したので、家族に報告しました。」— 何をしましたか？', '["報告","相談","謝罪","依頼"]'::jsonb, 0, 'jlpt', 'n4', 'reading', 3, E'報告 = melaporkan.', true, NULL, NULL),
  (E'「この問題は難しすぎます。先生に聞きます。」— どうしますか？', '["諦める","先生に聞く","友達に聞く","本で調べる"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'先生に聞く.', true, NULL, NULL),
  (E'「電話が鳴ったので、出ました。母でした。」— 誰の電話でしたか？', '["友達","母","先生","会社"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'母 = ibu.', true, NULL, NULL),
  (E'「今日は早く帰りたいです。用事があります。」— なぜ早く帰りたいですか？', '["疲れた","用事がある","病気だ","天気が悪い"]'::jsonb, 1, 'jlpt', 'n4', 'reading', 3, E'用事がある = ada urusan.', true, NULL, NULL);
