  (E'「誤嚥」の読み方は？', '["ごえん","ごいん","こえん","こいん"]'::jsonb, 0, 'jft', 'jft', 'kanji_reading', 3, E'誤嚥 dibaca ごえん (goen).', true, NULL, NULL),
  (E'「褥瘡」の読み方は？', '["じょくそう","じょくぞう","しょくそう","しょくぞう"]'::jsonb, 0, 'jft', 'jft', 'kanji_reading', 3, E'褥瘡 dibaca じょくそう (jokusou).', true, NULL, NULL),
  (E'「清拭」の読み方は？', '["せいしき","せいしゅう","しょうしき","しょうしゅう"]'::jsonb, 0, 'jft', 'jft', 'kanji_reading', 3, E'清拭 dibaca せいしき (seishiki).', true, NULL, NULL),
  (E'「移乗」の読み方は？', '["いじょう","いしょう","いそう","いじゅう"]'::jsonb, 0, 'jft', 'jft', 'kanji_reading', 3, E'移乗 dibaca いじょう (ijou).', true, NULL, NULL);
