  (E'「車椅子」の読み方は？', '["くるまいす","しゃいす","くるまかご","しゃかご"]'::jsonb, 0, 'jft', 'jft', 'vocabulary', 3, E'「車椅子」dibaca くるまいす (kurumaisu).', true, NULL, NULL),
  (E'「寝返り」の意味は？', '["起きること","寝ること","体の向きを変えること","歩くこと"]'::jsonb, 2, 'jft', 'jft', 'vocabulary', 3, E'寝返り = membalik badan.', true, NULL, NULL),
  (E'「誤嚥」の意味は？', '["食べ過ぎ","飲み込み間違い","アレルギー反応","消化不良"]'::jsonb, 1, 'jft', 'jft', 'vocabulary', 3, E'誤嚥 = salah menelan.', true, NULL, NULL),
  (E'「褥瘡」とは？', '["骨折","床ずれ","やけど","切り傷"]'::jsonb, 1, 'jft', 'jft', 'vocabulary', 3, E'褥瘡 = luka tekan (bedsore).', true, NULL, NULL),
  (E'「利用者」の意味は？', '["スタッフ","ケアを受ける人","医者","看護師"]'::jsonb, 1, 'jft', 'jft', 'vocabulary', 3, E'利用者 = pengguna layanan/pasien.', true, NULL, NULL),
  (E'「申し送り」の意味は？', '["手紙を送る","引き継ぎ報告","買い物リスト","休憩時間"]'::jsonb, 1, 'jft', 'jft', 'vocabulary', 3, E'申し送り = serah terima/shift report.', true, NULL, NULL),
  (E'「清拭」の意味は？', '["掃除すること","体を拭くこと","洗濯すること","料理すること"]'::jsonb, 1, 'jft', 'jft', 'vocabulary', 3, E'清拭 = membersihkan tubuh.', true, NULL, NULL),
  (E'「移乗」の意味は？', '["電車に乗る","ベッドから車椅子へ移ること","引っ越し","旅行"]'::jsonb, 1, 'jft', 'jft', 'vocabulary', 3, E'移乗 = transfer (bed ke kursi roda).', true, NULL, NULL),
  (E'「ナースコール」とは？', '["呼び出しベル","薬の名前","食事の時間","入浴の道具"]'::jsonb, 0, 'jft', 'jft', 'vocabulary', 3, E'ナースコール = bell panggilan perawat.', true, NULL, NULL),
  (E'「見守り」の意味は？', '["監視・世話","睡眠","運動","食事"]'::jsonb, 0, 'jft', 'jft', 'vocabulary', 3, E'見守り = mengawasi/menemani.', true, NULL, NULL),
  (E'「介助」の読み方は？', '["かいじょ","かいじょ","かいしょ","かいじゅ"]'::jsonb, 0, 'jft', 'jft', 'vocabulary', 3, E'介助 dibaca かいじょ (kaijo).', true, NULL, NULL),
