    INSERT INTO public.exam_questions
      (question_text, options, correct_answer, exam_type, level, section, difficulty, explanation, is_active, transcript, image_prompt)
    VALUES
  (E'🔊 「すみません、お水をもらえますか。」\n— 利用者さんは何を求めていますか？', '["食事","水","薬","トイレ"]'::jsonb, 1, 'jft', 'jft', 'conversation', 3, E'利用者 meminta air.', true, E'利用者：すみません、お水をもらえますか。\n介護士：はい、少々お待ちください。', NULL),
  (E'🔊 「今日は調子がいいです。」\n— 利用者さんの体調は？', '["悪い","普通","良い","わからない"]'::jsonb, 2, 'jft', 'jft', 'conversation', 3, E'Kondisi pasien baik hari ini.', true, E'介護士：今日のご気分はいかがですか？\n利用者：今日は調子がいいです。', NULL),
  (E'🔊 「少し寒いです。」\n— 何をすべきですか？', '["窓を開ける","エアコンを下げる","毛布をかける","水を持っていく"]'::jsonb, 2, 'jft', 'jft', 'conversation', 3, E'Pasien merasa dingin, beri selimut.', true, E'利用者：少し寒いです。\n介護士：毛布をお持ちしますね。', NULL),
  (E'🔊 「頭が痛いです。」\n— 利用者さんの症状は？', '["腹痛","頭痛","腰痛","歯痛"]'::jsonb, 1, 'jft', 'jft', 'conversation', 3, E'Gejala: sakit kepala.', true, E'利用者：頭が痛いです。\n介護士：看護師に伝えますね。', NULL),
  (E'🔊 「トイレに行きたいです。」\n— 利用者さんは何をしたいですか？', '["食事","散歩","トイレ","入浴"]'::jsonb, 2, 'jft', 'jft', 'conversation', 3, E'Pasien ingin ke toilet.', true, E'利用者：トイレに行きたいです。\n介護士：お手伝いしますね。', NULL),
  (E'🔊 「お薬の時間ですよ。」\n— 介護士は何をしていますか？', '["食事の準備","服薬の案内","入浴の準備","体操の案内"]'::jsonb, 1, 'jft', 'jft', 'conversation', 3, E'Pengingat waktu minum obat.', true, E'介護士：○○さん、お薬の時間ですよ。\n利用者：ありがとうございます。', NULL),
  (E'🔊 「腰が痛いので、ゆっくりお願いします。」\n— 何に注意すべきですか？', '["速く動く","ゆっくり動く","動かない","走る"]'::jsonb, 1, 'jft', 'jft', 'conversation', 3, E'Gerakkan pasien perlahan.', true, E'利用者：腰が痛いので、ゆっくりお願いします。\n介護士：はい、ゆっくりしましょうね。', NULL),
  (E'🔊 「ご飯はもういらないです。」\n— 利用者さんは？', '["もっと食べたい","食事を終えたい","飲み物が欲しい","デザートが欲しい"]'::jsonb, 1, 'jft', 'jft', 'conversation', 3, E'Pasien sudah selesai makan.', true, E'介護士：もう少し食べますか？\n利用者：ご飯はもういらないです。', NULL),
  (E'🔊 「散歩に行きましょうか。」\n— 介護士は何を提案していますか？', '["食事","入浴","散歩","睡眠"]'::jsonb, 2, 'jft', 'jft', 'conversation', 3, E'Caregiver mengajak jalan-jalan.', true, E'介護士：天気がいいですね。散歩に行きましょうか。\n利用者：はい、行きたいです。', NULL),
  (E'🔊 「夜、よく眠れましたか。」\n— 介護士は何を聞いていますか？', '["食事","睡眠","排泄","体温"]'::jsonb, 1, 'jft', 'jft', 'conversation', 3, E'Menanyakan kualitas tidur malam.', true, E'介護士：おはようございます。夜、よく眠れましたか？\n利用者：はい、ぐっすり眠れました。', NULL),
  (E'🔊 「お腹が痛いです。」\n— 利用者さんの症状は？', '["頭痛","腹痛","腰痛","歯痛"]'::jsonb, 1, 'jft', 'jft', 'conversation', 3, E'お腹が痛い = sakit perut.', true, E'利用者：お腹が痛いです。\n介護士：看護師に伝えますね。', NULL),
  (E'🔊 「もう少し食べられますか。」\n— 介護士は何を聞いていますか？', '["飲み物","食事","薬","睡眠"]'::jsonb, 1, 'jft', 'jft', 'conversation', 3, E'Menanyakan apakah masih bisa makan.', true, E'介護士：もう少し食べられますか。\n利用者：はい、少しなら。', NULL),
  (E'🔊 「お風呂に入りたいです。」\n— 利用者さんは何をしたいですか？', '["食事","入浴","散歩","睡眠"]'::jsonb, 1, 'jft', 'jft', 'conversation', 3, E'Ingin mandi.', true, E'利用者：お風呂に入りたいです。\n介護士：準備しますね。', NULL),
  (E'🔊 「息が苦しいです。」\n— 何をすべきですか？', '["無視する","すぐに報告する","散歩に連れる","食事を出す"]'::jsonb, 1, 'jft', 'jft', 'conversation', 3, E'Sesak napas = laporkan segera.', true, E'利用者：息が苦しいです。\n介護士：すぐに看護師を呼びます。', NULL),
  (E'🔊 「ありがとうございます。」\n— 利用者さんは何をしていますか？', '["謝る","感謝する","怒る","頼む"]'::jsonb, 1, 'jft', 'jft', 'conversation', 3, E'Mengucapkan terima kasih.', true, E'介護士：お手伝いしました。\n利用者：ありがとうございます。', NULL);
    INSERT INTO public.exam_questions
      (question_text, options, correct_answer, exam_type, level, section, difficulty, explanation, is_active, transcript, image_prompt)
    VALUES
  (E'📋 場面：利用者さんが転倒しました。\n最初に何をしますか？', '["すぐに起こす","安全を確認して声をかける","他の利用者に伝える","記録を書く"]'::jsonb, 1, 'jft', 'jft', 'situational', 3, E'Prioritas: pastikan keamanan pasien.', true, NULL, E'利用者が廊下で転倒した場面'),
  (E'📋 場面：利用者さんが「帰りたい」と言っています。\nどう対応しますか？', '["「帰れません」と言う","無視する","気持ちを聞いて寄り添う","家族に電話する"]'::jsonb, 2, 'jft', 'jft', 'situational', 3, E'Dengarkan dan dampingi perasaan pasien.', true, NULL, E'認知症の利用者が帰宅願望を示す場面'),
  (E'📋 場面：食事中に利用者さんがむせました。\nどうしますか？', '["水を飲ませる","食事を続ける","背中をさすって様子を見る","すぐに救急車を呼ぶ"]'::jsonb, 2, 'jft', 'jft', 'situational', 3, E'Tepuk punggung dan pantau kondisi.', true, NULL, E'食事介助中にむせた場面'),
  (E'📋 場面：利用者さんの顔色が悪いです。\n何をしますか？', '["そのまま様子を見る","バイタルを測定し報告する","食事を提供する","散歩に連れ出す"]'::jsonb, 1, 'jft', 'jft', 'situational', 3, E'Ukur vital sign dan laporkan.', true, NULL, E'利用者の体調変化に気づいた場面'),
  (E'📋 場面：他の介護士が休憩中です。ナースコールが鳴りました。\nどうしますか？', '["休憩中の人を呼ぶ","無視する","自分が対応する","後で対応する"]'::jsonb, 2, 'jft', 'jft', 'situational', 3, E'Tanggapi panggilan segera.', true, NULL, E'人手不足時のナースコール対応'),
  (E'📋 場面：入浴中に利用者さんが「熱い」と言いました。\nどうしますか？', '["我慢してもらう","すぐに温度を下げる","入浴を中止する","水を追加する"]'::jsonb, 1, 'jft', 'jft', 'situational', 3, E'Turunkan suhu air mandi.', true, NULL, E'入浴介助中の温度調整'),
  (E'📋 場面：利用者さんが薬を飲みたくないと言っています。\nどうしますか？', '["無理に飲ませる","看護師に相談する","薬を捨てる","次の日に飲ませる"]'::jsonb, 1, 'jft', 'jft', 'situational', 3, E'Konsultasikan ke perawat.', true, NULL, E'服薬拒否の場面'),
  (E'📋 場面：夜勤中、利用者さんが眠れないと言っています。\nどうしますか？', '["睡眠薬を渡す","テレビをつける","話を聞いて安心させる","無視する"]'::jsonb, 2, 'jft', 'jft', 'situational', 3, E'Dengarkan dan tenangkan pasien.', true, NULL, E'夜間の不眠対応'),
  (E'📋 場面：利用者さんの家族が面会に来ました。\n何をしますか？', '["特に何もしない","利用者の様子を伝える","家族を帰す","薬を渡す"]'::jsonb, 1, 'jft', 'jft', 'situational', 3, E'Sampaikan kondisi pasien ke keluarga.', true, NULL, E'家族面会時の対応'),
  (E'📋 場面：車椅子からベッドに移乗します。\n正しい方法は？', '["一人で抱え上げる","ブレーキを確認し声かけしてから移乗","利用者に自分でやらせる","引きずって移動する"]'::jsonb, 1, 'jft', 'jft', 'situational', 3, E'Cek rem, beri instruksi, lalu transfer.', true, NULL, E'移乗介助の場面'),
  (E'📋 場面：利用者さんが食事を残しました。\nどうしますか？', '["無理に食べさせる","理由を聞いて記録する","無視する","捨てる"]'::jsonb, 1, 'jft', 'jft', 'situational', 3, E'Tanyakan alasan dan catat.', true, NULL, E'食事を残した場面'),
  (E'📋 場面：利用者さんが他の利用者と喧嘩しました。\nどうしますか？', '["大声で叱る","双方を隔離し報告する","無視する","罰を与える"]'::jsonb, 1, 'jft', 'jft', 'situational', 3, E'Pisahkan dan laporkan.', true, NULL, E'利用者間のトラブル'),
  (E'📋 場面：利用者さんが歩行器を使っています。\n注意することは？', '["走らせる","ゆっくり付き添う","離れる","奪う"]'::jsonb, 1, 'jft', 'jft', 'situational', 3, E'Dampingi dengan perlahan.', true, NULL, E'歩行器介助'),
  (E'📋 場面：利用者さんが認知症で同じ質問を繰り返します。\nどうしますか？', '["イライラする","何度も丁寧に答える","無視する","部屋を出る"]'::jsonb, 1, 'jft', 'jft', 'situational', 3, E'Jawab dengan sabar berulang kali.', true, NULL, E'認知症の利用者'),
  (E'📋 場面：利用者さんの褥瘡を発見しました。\nどうしますか？', '["そのままにする","体位変換し看護師に報告","自分で治療する","隠す"]'::jsonb, 1, 'jft', 'jft', 'situational', 3, E'Ganti posisi dan laporkan.', true, NULL, E'褥瘡発見の場面');
